const htmlRoot = document.documentElement;
const themeBtn = document.getElementById("themeBtn");
let ignoreNextThemeClick = false;

function applyTheme(theme) {
  const isDark = theme === "dark";
  htmlRoot.classList.toggle("dark", isDark);
  themeBtn.classList.toggle("city-is-night", isDark);
  themeBtn.setAttribute("aria-pressed", String(isDark));
  themeBtn.setAttribute("aria-label", isDark ? "Switch to light mode" : "Switch to dark mode");
}

function initTheme() {
  applyTheme("light");
}

function toggleTheme() {
  applyTheme(htmlRoot.classList.contains("dark") ? "light" : "dark");
}

themeBtn.addEventListener("pointerdown", (event) => {
  if (event.button !== 0) return;
  event.preventDefault();
  ignoreNextThemeClick = true;
  toggleTheme();
});

themeBtn.addEventListener("click", (event) => {
  if (ignoreNextThemeClick) {
    ignoreNextThemeClick = false;
    event.preventDefault();
    return;
  }
  toggleTheme();
});

initTheme();

