const imagePreloadCache = commands.map((command) => {
  const image = new Image();
  image.loading = "eager";
  image.decoding = "sync";
  image.src = command.image;
  image.decode?.().catch(() => {});
  return image;
});

function createCard(command) {
  const visual = `<img class="card-image" src="${command.image}" style="object-position: ${command.focal}" alt="${command.name} preview" loading="eager" decoding="sync" />`;
  const entranceShell = document.createElement("div");
  entranceShell.className = "entrance-shell";
  entranceShell.dataset.category = command.category;
  entranceShell.dataset.search = `${command.name} ${command.desc} ${command.category}`.toLowerCase();
  entranceShell.addEventListener("animationend", (event) => {
    if (event.target === entranceShell) entranceShell.classList.remove("is-filter-entering");
  });

  const scene = document.createElement("div");
  scene.className = "scene";
  scene.innerHTML = `
    <article class="card">
      <div class="card-glow"></div>
      <div class="hover-sweep"></div>
      <div class="card-content">
        <div class="icon-box">${visual}</div>
        <h2>${command.name}</h2>
        <p>${command.desc}</p>
      </div>
    </article>
  `;
  entranceShell.appendChild(scene);
  return entranceShell;
}

commands.forEach((command) => {
  const grid = document.querySelector(`[data-category="${command.category}"]`);
  grid.appendChild(createCard(command));
});

document.querySelectorAll(".card").forEach((card) => {
  const glow = card.querySelector(".card-glow");

  card.addEventListener("mousemove", (event) => {
    const rect = card.getBoundingClientRect();
    const x = event.clientX - rect.left;
    const y = event.clientY - rect.top;
    const maxTilt = 11;
    const rotateX = ((rect.height / 2 - y) / (rect.height / 2)) * maxTilt;
    const rotateY = ((x - rect.width / 2) / (rect.width / 2)) * maxTilt;

    card.style.transform = `translateY(-5px) rotateX(${rotateX}deg) rotateY(${rotateY}deg) scale(1.008)`;
    glow.style.setProperty("--x", `${x}px`);
    glow.style.setProperty("--y", `${y}px`);
    glow.style.opacity = 1;
  });

  card.addEventListener("mouseleave", () => {
    card.style.transform = "translateY(0) rotateX(0) rotateY(0) scale(1)";
    glow.style.opacity = 0;
  });
});

const searchInput = document.getElementById("commandSearch");
const searchCount = document.getElementById("commandSearchCount");
const emptyState = document.getElementById("commandEmpty");
const filterLinks = [...document.querySelectorAll(".tabs a[data-filter]")];
const categorySections = [...document.querySelectorAll(".category")];
const initialFilterLink = filterLinks.find((link) => link.getAttribute("href") === window.location.hash);
let activeCategory = initialFilterLink?.dataset.filter || "all";

function animateVisibleScenes(scenes, { lightweight = false } = {}) {
  scenes.forEach((scene) => scene.classList.remove("is-filter-entering"));

  requestAnimationFrame(() => {
    const animationLimit = lightweight ? 4 : 8;

    scenes.slice(0, animationLimit).forEach((scene, index) => {
      const spinTurns = lightweight || index % 2 === 0 ? "360deg" : "720deg";
      const delay = index * (lightweight ? 20 : 34);

      scene.style.setProperty("--enter-turn", spinTurns);
      scene.style.setProperty("--enter-delay", `${delay}ms`);
      scene.classList.add("is-filter-entering");
    });
  });
}

function applyCommandFilters({ animate = false } = {}) {
  const query = searchInput.value.trim().toLowerCase();
  let visibleCount = 0;
  const visibleScenes = [];

  categorySections.forEach((section) => {
    let visibleInSection = 0;

    section.querySelectorAll(".entrance-shell").forEach((scene) => {
      const categoryMatch = activeCategory === "all" || scene.dataset.category === activeCategory;
      const searchMatch = !query || scene.dataset.search.includes(query);
      const shouldShow = categoryMatch && searchMatch;

      scene.classList.toggle("is-filter-hidden", !shouldShow);
      if (shouldShow) {
        visibleInSection += 1;
        visibleCount += 1;
        visibleScenes.push(scene);
      }
    });

    section.classList.toggle("is-filter-hidden", visibleInSection === 0);
  });

  searchCount.textContent = `${visibleCount} command${visibleCount === 1 ? "" : "s"}`;
  emptyState.hidden = visibleCount !== 0;
  if (animate) animateVisibleScenes(visibleScenes, { lightweight: activeCategory === "all" });
}

filterLinks.forEach((link) => {
  link.classList.toggle("is-active", link.dataset.filter === activeCategory);

  link.addEventListener("click", (event) => {
    event.preventDefault();
    activeCategory = link.dataset.filter;
    filterLinks.forEach((item) => item.classList.toggle("is-active", item === link));
    history.replaceState(null, "", link.getAttribute("href"));
    applyCommandFilters({ animate: true });
  });
});

searchInput.addEventListener("input", applyCommandFilters);
applyCommandFilters();
